 func getConverge(_ nums: [Int]) -> Int {
        if nums.count == 0 { return -1 }

        // Get unique elemts in array
        let newArray = Array(Set(nums).sorted())     
        if newArray.count == 1 { return newArray.first! }

        let firstObj = newArray.count > 0 ? newArray.first! : 0

        // initialize result with first object possible combinations
        var result = [firstObj, firstObj + 1, firstObj - 1]

        for val in newArray {
            let next = val == 9 ? 0 : val + 1
            let prev = val == 0 ? 9 : val - 1
            // Filter everytime the common objects
            // if any common elemts is left then that is the converge element
            result = result.filter({$0 == val || $0 == next || $0 == prev})
        }
        return result.count > 0 ? result.first! : -1
    }
